import{_ as e}from"./chunks/quickstart_01.CAs9iatn.js";import{_ as a,o as i,c as r,a2 as s}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/quickstart.md","filePath":"getting-started/quickstart.md"}'),o={name:"getting-started/quickstart.md"};function n(l,t,c,g,d,u){return i(),r("div",null,[...t[0]||(t[0]=[s('<h1 id="quick-start" tabindex="-1"><i class="ph ph-target"></i> Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-target&quot;&gt;&lt;/i&gt; Quick Start&quot;">​</a></h1><p>The WebAP plugin is designed with a <em>Plug-and-Play</em> approach. No need to write code or add managers to your startup scenes — the system initializes automatically.</p><h2 id="_1-enable-the-plugin" tabindex="-1">1. Enable the Plugin <a class="header-anchor" href="#_1-enable-the-plugin" aria-label="Permalink to &quot;1. Enable the Plugin&quot;">​</a></h2><ol><li>Navigate to <strong>Edit -&gt; Project Settings -&gt; Adaptive Performance (Web)</strong>.</li><li>Toggle <strong>Enable Web Adaptive Performance</strong>.</li><li>Expand the Scalers tab and enable additional modules (e.g., Physics Step or Shadows Quality) that best suit your game&#39;s specifics (see <a href="./../scalers/reference">Scalers Reference</a> for details).</li></ol><p><img src="'+e+'" alt=""></p><div class="info custom-block"><p class="custom-block-title">Default Settings</p><p>The default settings are pre-configured for optimal performance in most projects. Leave them unchanged.</p></div><h2 id="_2-configure-player-settings" tabindex="-1">2. Configure Player Settings <a class="header-anchor" href="#_2-configure-player-settings" aria-label="Permalink to &quot;2. Configure Player Settings&quot;">​</a></h2><p>To allow the plugin&#39;s Tracker to mathematically distinguish processor (CPU) lag from graphics (GPU) lag, it requires access to precise hardware frame timings.</p><div class="warning custom-block"><p class="custom-block-title">Frame Timing Stats</p><p>Navigate to <strong>Edit -&gt; Project Settings -&gt; Player -&gt; Other Settings -&gt; Rendering</strong> and check <strong>Frame Timing Stats</strong>. Without this setting, Bottleneck detection will not function.</p></div><h2 id="_3-configure-graphics" tabindex="-1">3. Configure Graphics <a class="header-anchor" href="#_3-configure-graphics" aria-label="Permalink to &quot;3. Configure Graphics&quot;">​</a></h2><p>Stop creating separate quality presets (Low, Medium, High) for different devices and forcing players to choose manually.</p><div class="tip custom-block"><p class="custom-block-title">Maximize Graphics Quality</p><p>Configure your project for maximum quality. For BiRP, do this in <code>Project Settings -&gt; Quality</code>, and for URP — inside your <code>URP Asset</code>. If the player&#39;s device lacks the Performance Headroom, the plugin will smoothly scale down the load automatically, utilizing only the Scalers you have enabled.</p></div>',12)])])}const f=a(o,[["render",n]]);export{m as __pageData,f as default};
